-- ============================================================
-- Base de Datos Central — Crear tabla + seed de datos
-- Pegar completo en: console.neon.tech → SQL Editor
-- ============================================================

CREATE TABLE IF NOT EXISTS base_datos_central (
  id                 SERIAL PRIMARY KEY,
  codigo_siges       TEXT,
  codigo_formulacion INTEGER,
  subproducto        TEXT,
  codigo_ppr         INTEGER,
  nombre             TEXT NOT NULL,
  caracteristicas    TEXT,
  presentacion       TEXT,
  renglon            INTEGER,
  precio_unitario    DOUBLE PRECISION,
  cantidad_2027      DOUBLE PRECISION,
  monto_2027         DOUBLE PRECISION,
  cantidad_2028      DOUBLE PRECISION,
  monto_2028         DOUBLE PRECISION,
  cantidad_2029      DOUBLE PRECISION,
  monto_2029         DOUBLE PRECISION,
  cantidad_2030      DOUBLE PRECISION,
  monto_2030         DOUBLE PRECISION,
  cantidad_2031      DOUBLE PRECISION,
  monto_2031         DOUBLE PRECISION,
  activo             BOOLEAN NOT NULL DEFAULT TRUE,
  created_at         TEXT DEFAULT to_char(now(), 'YYYY-MM-DD HH24:MI:SS'),
  updated_at         TEXT DEFAULT to_char(now(), 'YYYY-MM-DD HH24:MI:SS')
);

